def segment_distance(first_start, first_end, second_start, second_end):
    u = first_end - first_start
    v = second_end - second_start
    w = first_start - second_start
    a = u.dot(u)
    b = u.dot(v)
    c = v.dot(v)
    d = u.dot(w)
    e = v.dot(w)
    denominator = a * c - b * b
    epsilon = 1e-24
    if a <= epsilon and c <= epsilon:
        return float(w.Length)
